17	const MAIN_ITEM_TYPES = new Set(["sword", "amulet", "staff", "potion"]);
18	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
19	
20	type Item = { type: string };
21	type Customer = { yearsWithMHPCO?: number };
22	type Scenario = {
23	  customer?: Customer;
24	  steps: { op: string; items: Item[] }[];
25	};
26	
27	function countItemsByType(items: Item[]): Map<string, number> {
28	  const counts = new Map<string, number>();
29	  for (const item of items) {
30	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
31	  }
32	  return counts;
33	}
34	
35	function blockDiscountFor(type: string, count: number): number {
36	  const isComponent = COMPONENT_TYPES.has(type);
37	  const formsBlock = count === BLOCK_SIZE;
38	  return isComponent && formsBlock ? BLOCK_OF_THREE_DISCOUNT : 0;
39	}
40	
41	function basePremiumForGroup(type: string, count: number): number {
42	  return count * ITEM_BASE_PRICES[type] - blockDiscountFor(type, count);
43	}
44	
45	function computePolicyBase(items: Item[]): number {
46	  const itemCountsByType = countItemsByType(items);
47	  let basePremium = 0;
48	  for (const [type, count] of itemCountsByType.entries()) {
49	    basePremium += basePremiumForGroup(type, count);
50	  }
51	  return basePremium;
52	}
53	
54	function computeFirstInsuranceSurcharge(items: Item[]): number {
55	  let surcharge = 0;
56	  for (const item of items) {
57	    if (MAIN_ITEM_TYPES.has(item.type)) {
58	      surcharge += ITEM_BASE_PRICES[item.type] * FIRST_INSURANCE_RATE;
59	    }
60	  }
61	  return surcharge;
62	}
63	
64	function computeLoyaltyDiscount(policyBase: number, customer: Customer): number {
65	  const years = customer.yearsWithMHPCO ?? 0;
66	  if (years >= LOYALTY_YEARS_THRESHOLD) {
67	    return policyBase * LOYALTY_DISCOUNT_RATE;
68	  }
69	  return 0;
70	}
71	
72	export function runScenario(scenario: unknown): unknown {
73	  const s = scenario as Scenario;
74	  const customer = s.customer ?? { yearsWithMHPCO: 0 };
75	  const items = s.steps[0].items;
76	
77	  const policyBase = computePolicyBase(items);
78	  const firstInsurance = computeFirstInsuranceSurcharge(items);
79	  const loyaltyDiscount = computeLoyaltyDiscount(policyBase, customer);
80	
81	  const premium = policyBase + firstInsurance - loyaltyDiscount + PROCESSING_FEE;
82	  return { results: [{ premium }] };
83	}
